<script setup lang="ts">
// DOC-STAGE3 — per-stage filter view.
//
// Route: /doc-stages/<stage>
//
// Reads the JSON sidecar generated by scripts/regenerate-doc-stage-index.py
// from /doc-stage-index.json (served from frontend/public/). Displays every
// aidocs doc at the requested lifecycle stage with its last-stage-change date.

interface DocEntry {
  path: string;
  title: string;
  last_stage_change: string | null;
}

interface StageIndex {
  generated: string;
  stages: Record<string, DocEntry[]>;
}

const KNOWN_STAGES = [
  "fragment",
  "concept",
  "idea",
  "feature-defined",
  "audited-by-personas",
  "feedback-implemented",
  "tests-implemented",
  "deployed",
  "decommissioned",
  "UNTAGGED",
  "upgrade-overlay",
] as const;

const route = useRoute();
const stage = computed(() => route.params.stage as string);

const { data: index, error } = await useFetch<StageIndex>("/doc-stage-index.json");

const isUnknownStage = computed(() => {
  if (!index.value) return false;
  const s = stage.value;
  return !KNOWN_STAGES.includes(s as (typeof KNOWN_STAGES)[number]) &&
    !(s in (index.value?.stages ?? {}));
});

const docs = computed<DocEntry[]>(() => {
  if (!index.value) return [];
  return index.value.stages[stage.value] ?? [];
});

const generatedAt = computed(() => index.value?.generated ?? null);

useHead({
  title: computed(() => `Stage: ${stage.value} | shepard`),
});

function githubUrl(path: string): string {
  return `https://github.com/noheton/shepard/blob/main/${path}`;
}
</script>

<template>
  <v-container fluid style="max-width: 2400px; margin: 0 auto" class="pa-6">
    <div class="d-flex align-center mb-2 ga-2">
      <v-btn
        :to="'/help'"
        variant="text"
        prepend-icon="mdi-arrow-left"
        size="small"
      >
        All stages
      </v-btn>
    </div>

    <div v-if="error">
      <v-alert type="error" class="mb-4">
        Could not load stage index: {{ error.message }}
      </v-alert>
    </div>

    <div v-else-if="!index">
      <v-progress-circular indeterminate class="ma-4" />
    </div>

    <div v-else-if="isUnknownStage">
      <h1 class="text-h4 mb-2">Unknown stage</h1>
      <p class="text-body-1 text-medium-emphasis mb-4">
        <code>{{ stage }}</code> is not a recognised lifecycle stage. See
        <a
          href="https://github.com/noheton/shepard/blob/main/aidocs/00-doc-stages.md"
          target="_blank"
          rel="noopener"
        >aidocs/00-doc-stages.md</a> for the canonical taxonomy.
      </p>
      <v-btn to="/help" variant="outlined">Back to help</v-btn>
    </div>

    <template v-else>
      <h1 class="text-h4 mb-1">
        Docs at stage: <code>{{ stage }}</code>
      </h1>
      <p class="text-body-2 text-medium-emphasis mb-1">
        {{ docs.length }} document{{ docs.length === 1 ? '' : 's' }}
      </p>
      <p v-if="generatedAt" class="text-caption text-medium-emphasis mb-4">
        Index generated {{ generatedAt }} &mdash; regenerate with
        <code>python3 scripts/regenerate-doc-stage-index.py</code>
      </p>

      <div v-if="docs.length === 0">
        <v-alert type="info" variant="tonal">
          No documents are currently at stage <strong>{{ stage }}</strong>.
        </v-alert>
      </div>

      <v-table v-else density="compact">
        <thead>
          <tr>
            <th class="text-left" style="min-width: 220px">Title</th>
            <th class="text-left" style="min-width: 280px">Path</th>
            <th class="text-left" style="min-width: 130px">Last stage change</th>
          </tr>
        </thead>
        <tbody>
          <tr v-for="doc in docs" :key="doc.path">
            <td>
              <a
                :href="githubUrl(doc.path)"
                target="_blank"
                rel="noopener"
                class="text-primary"
              >{{ doc.title }}</a>
            </td>
            <td>
              <code class="text-caption">{{ doc.path }}</code>
            </td>
            <td class="text-caption">
              {{ doc.last_stage_change ?? '—' }}
            </td>
          </tr>
        </tbody>
      </v-table>
    </template>
  </v-container>
</template>
